{
  "case_summary": "82岁女性髋部骨折术后第1天，合并高血压及轻度认知障碍。目前主要问题包括中重度疼痛（评分6分）、拒绝翻身、夜间烦躁及拔管倾向、压疮高风险（Braden 13分）及跌倒高风险。生命体征基本平稳，切口少量淡红渗血，留置尿管。",
  "nursing_problems": [
    {
      "problem": "急性疼痛",
      "evidence": "疼痛评分6分，不愿翻身",
      "priority": "高"
    },
    {
      "problem": "有皮肤完整性受损的风险",
      "evidence": "Braden评分13分，高龄，术后卧床，拒绝翻身",
      "priority": "高"
    },
    {
      "problem": "有非计划性拔管的风险",
      "evidence": "夜间烦躁，主动要求拔尿管，轻度认知障碍",
      "priority": "中高"
    },
    {
      "problem": "有跌倒/坠床的风险",
      "evidence": "高龄，术后早期，轻度认知障碍，躁动",
      "priority": "高"
    },
    {
      "problem": "睡眠形态紊乱/焦虑",
      "evidence": "夜间烦躁，疼痛影响休息",
      "priority": "中"
    }
  ],
  "goals": [
    {
      "timeframe": "术后24-48小时内",
      "target": "患者疼痛评分降至≤3分，能配合协助翻身"
    },
    {
      "timeframe": "住院期间",
      "target": "患者皮肤保持完整，无压力性损伤发生"
    },
    {
      "timeframe": "术后3天内",
      "target": "尿管妥善固定，无非计划性拔管事件发生"
    },
    {
      "timeframe": "术后全程",
      "target": "未发生跌倒或坠床事件"
    },
    {
      "timeframe": "术后第一周",
      "target": "患者夜间连续睡眠时长≥4小时，烦躁发作频率降低"
    }
  ],
  "interventions": [
    {
      "action": "遵医嘱给予镇痛药物，评估用药后效果；采用非药物干预（如放松引导、分散注意力）。",
      "rationale": "有效控制疼痛可改善患者依从性，促进早期活动与康复。",
      "frequency_or_timing": "按需给药，用药后30分钟重新评估疼痛评分"
    },
    {
      "action": "制定并执行定时翻身计划，使用减压垫保护骨突部位；指导家属协助。",
      "rationale": "减轻局部组织长期受压，预防压力性损伤。",
      "frequency_or_timing": "每2小时翻身一次，必要时增加频次"
    },
    {
      "action": "妥善固定尿管，使用防拔管手套或软质约束（遵医嘱并签署知情同意），加强巡视与心理安抚。",
      "rationale": "防止非计划性拔管导致尿道损伤或感染风险。",
      "frequency_or_timing": "每班检查固定情况，夜间每小时巡视一次"
    },
    {
      "action": "落实防跌倒措施：床栏始终拉起，呼叫器置于易取处，地面防滑，下床活动需专人陪同并使用助行器。",
      "rationale": "降低术后早期因虚弱、认知障碍及躁动导致的跌倒风险。",
      "frequency_or_timing": "持续执行，每次下床前评估"
    },
    {
      "action": "优化夜间环境（调暗灯光、减少噪音），安排集中护理操作，睡前进行温水擦浴或足部按摩。",
      "rationale": "改善睡眠环境，缓解夜间谵妄/烦躁倾向。",
      "frequency_or_timing": "每日晚间执行"
    }
  ],
  "observation_points": [
    "切口敷料渗血量、颜色及周围皮肤情况",
    "疼痛评分变化及镇痛药物不良反应（如呼吸抑制、恶心呕吐）",
    "意识状态、定向力及夜间烦躁/谵妄表现",
    "皮肤完整性（尤其骶尾部、足跟等骨突处）",
    "尿管通畅度、尿液性状及有无滑脱迹象",
    "下肢肿胀、皮温、足背动脉搏动及感觉运动功能"
  ],
  "escalation_criteria": [
    "突发胸痛、呼吸困难、SpO2持续<92%或心率>120次/分（警惕肺栓塞或心源性事件）",
    "意识突然改变、嗜睡叫不醒或出现严重躁动/攻击行为（警惕脑卒中、严重谵妄或代谢紊乱）",
    "切口敷料渗出转为鲜红色且量多（>5ml/h）或伴搏动性出血",
    "血压骤降（收缩压<90mmHg）或骤升（收缩压>180mmHg）伴头痛、视物模糊",
    "体温≥38.5℃或寒战（警惕感染或深静脉血栓）",
    "尿管完全滑脱或大量血尿"
  ],
  "education_points": [
    "向家属解释术后早期疼痛管理的必要性及按时服药的重要性，避免强忍疼痛影响康复。",
    "指导家属正确协助患者翻身与肢体摆放的方法，强调避免患肢内收内旋。",
    "说明留置尿管的目的、注意事项及防拔管技巧，取得家属配合与监督。",
    "告知防跌倒/坠床的具体措施，强调下床活动必须有家属或护士陪同。",
    "建议家属参与夜间陪护，通过熟悉的声音和物品安抚患者情绪，减少认知障碍引发的躁动。"
  ],
  "safety_boundary": "本计划基于提供的资料生成，仅供临床护理参考与辅助决策。所有措施需在医院现行制度、主管医师医嘱及责任护士独立评估的基础上执行。如遇病情变化或超出护理权限的情况，请立即上报医生或启动急救流程。模型不提供诊断、处方或治疗替代建议。"
}

{
  "case_summary": "63岁男性，2型糖尿病合并右足底溃疡伴感染，伴发热（38.1℃）、心动过速（102次/分）及空腹高血糖（11.8mmol/L）。存在周围神经病变史及不良穿鞋习惯，青霉素过敏。核心问题为局部与全身感染控制、血糖管理、创面修复及并发症预防。",
  "nursing_problems": [
    {
      "problem": "现患感染/感染扩散风险",
      "evidence": "右足底溃疡3cm伴周围红肿、少量脓性渗液，T 38.1℃，P 102次/分",
      "priority": "高"
    },
    {
      "problem": "血糖调节无效",
      "evidence": "空腹血糖11.8mmol/L，2型糖尿病史",
      "priority": "高"
    },
    {
      "problem": "皮肤完整性受损",
      "evidence": "右足底溃疡病程1周，创面伴炎性反应",
      "priority": "高"
    },
    {
      "problem": "周围神经病变相关损伤风险",
      "evidence": "自述脚麻多年，日常穿拖鞋增加外伤与摩擦风险",
      "priority": "中"
    },
    {
      "problem": "药物过敏风险",
      "evidence": "明确青霉素过敏史",
      "priority": "中"
    }
  ],
  "goals": [
    {
      "timeframe": "入院48小时内",
      "target": "体温降至37.5℃以下，心率降至90次/分以下，无寒战或意识改变"
    },
    {
      "timeframe": "住院期间",
      "target": "空腹血糖稳定在7.0-10.0mmol/L，餐后2小时血糖<13.9mmol/L，无低血糖事件发生"
    },
    {
      "timeframe": "出院前",
      "target": "创面清洁干燥，渗液减少或消失，周围红肿消退，肉芽组织开始生长"
    },
    {
      "timeframe": "出院时",
      "target": "患者及家属能独立演示每日足部检查步骤，并准确描述安全鞋袜选择标准"
    }
  ],
  "interventions": [
    {
      "action": "严格执行无菌操作进行创面换药，生理盐水轻柔冲洗，按医嘱使用非青霉素类抗菌敷料或外用制剂",
      "rationale": "清除坏死组织与细菌负荷，维持湿性平衡环境，促进上皮爬行",
      "frequency_or_timing": "每日1-2次，渗液浸透敷料时立即更换"
    },
    {
      "action": "定时监测并记录生命体征，绘制体温与心率曲线",
      "rationale": "动态评估全身炎症反应及抗感染治疗疗效",
      "frequency_or_timing": "常规q4h，发热期q2h至退热后24h"
    },
    {
      "action": "遵医嘱落实降糖方案，规范采集指尖血或静脉血监测血糖",
      "rationale": "高血糖抑制白细胞吞噬功能并延缓胶原合成，平稳控糖是伤口愈合基础",
      "frequency_or_timing": "每日至少4次（三餐前+睡前），血糖波动大时加密至每日6-8次"
    },
    {
      "action": "协助患者采取患肢抬高体位，限制患足负重，提供减压鞋垫或保护性支具",
      "rationale": "降低足底静水压与机械应力，改善局部微循环，防止溃疡加深",
      "frequency_or_timing": "持续执行，坐卧位时实施，下床活动严格遵医嘱"
    },
    {
      "action": "建立过敏警示标识，执行“三查七对”，所有抗菌药物使用前双人核对并确认替代方案",
      "rationale": "杜绝青霉素类药物误用，防范过敏性休克等严重不良反应",
      "frequency_or_timing": "每次给药及输液前"
    },
    {
      "action": "指导标准化足部日常护理：温水清洗（水温≤37℃）、彻底擦干趾缝、足背足底涂抹保湿霜（避开创面）、平剪指甲",
      "rationale": "维持皮肤屏障功能，预防干燥皲裂与继发感染",
      "frequency_or_timing": "每日1次，洗澡后或睡前进行"
    }
  ],
  "observation_points": [
    "创面直径、深度、基底颜色（红/黄/黑）、渗液量/性状/气味及周围红肿硬结范围变化",
    "体温峰值与热型、心率、呼吸频率、血压及尿量变化",
    "血糖监测数值趋势及低血糖早期征象（心悸、出汗、饥饿感、手抖、视物模糊）",
    "足背动脉搏动强度、皮温、毛细血管充盈时间、痛温觉及触觉减退程度",
    "抗菌药物输注过程中的局部反应及全身过敏表现（皮疹、瘙痒、胸闷、喉头紧缩感）"
  ],
  "escalation_criteria": [
    "体温持续≥39.0℃或出现寒战、意识障碍、呼吸急促（>24次/分）、收缩压<90mmHg或尿量<0.5ml/kg/h，提示脓毒症/感染性休克可能，立即通知医生并启动急救预案",
    "创面迅速扩大、出现广泛黑色坏死、恶臭显著或红肿沿足背/小腿呈条索状蔓延，提示感染扩散或坏疽，立即报告医生评估紧急清创或外科干预",
    "血糖持续>16.7mmol/L伴恶心呕吐、深大呼吸、呼气烂苹果味，或血糖<3.9mmol/L经口服葡萄糖处理后15分钟未缓解，提示糖尿病酮症酸中毒或重度低血糖，立即通知医生处置",
    "出现任何药物过敏迹象（弥漫性荨麻疹、血管性水肿、支气管痉挛、血压骤降），立即停止输注/给药，保留静脉通路，呼叫抢救团队并配合肾上腺素等急救用药"
  ],
  "education_points": [
    "每日赤脚或穿袜前必须全面检查双足，重点查看趾缝、足底及骨突处，发现水疱、破溃、红肿或温度异常立即就医",
    "严禁穿拖鞋、露趾鞋或硬底鞋外出，选择鞋头宽大、鞋底柔软防滑、内部无缝线的专用糖尿病鞋及纯棉吸汗袜",
    "洗脚水温必须使用水温计或肘部测试（≤37℃），绝对禁止直接用热水泡脚、烤火或使用电热毯热敷患足",
    "严格遵医嘱规律使用降糖药与抗菌药，不可自行停药或更改剂量；随身携带快速升糖食品（如葡萄糖片、含糖饮料）以备低血糖应急",
    "控制总热量摄入，均衡膳食结构，戒烟限酒；出院后定期复查糖化血红蛋白、下肢血管超声及神经传导功能"
  ],
  "safety_boundary": "本护理计划基于用户提供的资料生成，仅供临床护理辅助参考。所有措施须严格遵循所在医疗机构规章制度、主管医师医嘱及责任护士床旁综合评估结果，不得替代专业医疗诊断、处方或治疗决策。"
}

{
  "case_summary": "70岁男性慢性心力衰竭急性加重，主要表现为容量负荷过重（3天体重增加2.5kg、双下肢水肿加重、尿量减少）、肺淤血（夜间阵发性呼吸困难、SpO2 92%、R 24次/分）及代偿性心动过速（P 108次/分），合并高钠饮食偏好与利尿剂依从性差。",
  "nursing_problems": [
    {
      "problem": "体液过多",
      "evidence": "近3天体重增加2.5kg、双下肢水肿加重、尿量减少、夜间憋醒",
      "priority": "高"
    },
    {
      "problem": "气体交换受损/低效性呼吸型态",
      "evidence": "SpO2 92%、R 24次/分、夜间阵发性呼吸困难",
      "priority": "高"
    },
    {
      "problem": "活动无耐力/跌倒风险",
      "evidence": "P 108次/分、心衰致疲劳、频繁夜尿",
      "priority": "中"
    },
    {
      "problem": "知识缺乏/治疗依从性不足",
      "evidence": "喜喝汤（高钠高液）、利尿药有时漏服",
      "priority": "中"
    }
  ],
  "goals": [
    {
      "timeframe": "24小时内",
      "target": "SpO2维持在≥94%，静息呼吸频率降至≤20次/分，主诉呼吸困难明显减轻"
    },
    {
      "timeframe": "3-5天内",
      "target": "每日体重下降0.5-1.0kg，累计减重2-3kg，尿量恢复至>1500ml/日，下肢水肿程度减轻"
    },
    {
      "timeframe": "48小时内",
      "target": "患者及家属能准确复述低盐限液原则、每日称重方法及药物按时服用的重要性，并建立规律服药习惯"
    }
  ],
  "interventions": [
    {
      "action": "协助取半卧位或端坐位，遵医嘱给予氧疗",
      "rationale": "利用重力减少静脉回流，减轻肺淤血，改善组织氧合",
      "frequency_or_timing": "持续/按需，每2小时评估一次呼吸频率、SpO2及主观憋喘感受"
